312. using System;
313. using System.Collections.Concurrent;
314. using ContosoUniversity.Models;
315. 
316. namespace ContosoUniversity.Services
317. {
318.     public class NotificationService : IDisposable
319.     {
320.         // Static shared queue across application instances (simple in-memory alternative to MSMQ)
321.         private static readonly ConcurrentQueue<Notification> _queue = new();
322.         private static readonly int _maxQueueLength = 500; // basic cap to prevent unbounded growth
323. 
324.         public NotificationService()
325.         {
326.             // No initialization required for in-memory queue
327.         }
328. 
329.         public void SendNotification(string entityType, string entityId, EntityOperation operation, string userName = null)
330.         {
331.             SendNotification(entityType, entityId, null, operation, userName);
332.         }
333. 
334.         public void SendNotification(string entityType, string entityId, string entityDisplayName, EntityOperation operation, string userName = null)
335.         {
336.             try
337.             {
338.                 var notification = new Notification
339.                 {
340.                     EntityType = entityType,
341.                     EntityId = entityId,
342.                     Operation = operation.ToString(),
343.                     Message = GenerateMessage(entityType, entityId, entityDisplayName, operation),
344.                     CreatedAt = DateTime.Now,
345.                     CreatedBy = userName ?? "System",
346.                     IsRead = false
347.                 };
348. 
349.                 _queue.Enqueue(notification);
350. 
351.                 // Enforce max queue length (best-effort)
352.                 while (_queue.Count > _maxQueueLength && _queue.TryDequeue(out _)) { }
353.             }
354.             catch (Exception ex)
355.             {
356.                 System.Diagnostics.Debug.WriteLine($"Failed to enqueue notification: {ex.Message}");
357.             }
358.         }
359. 
360.         public Notification ReceiveNotification()
361.         {
362.             try
363.             {
364.                 return _queue.TryDequeue(out var notification) ? notification : null;
365.             }
366.             catch (Exception ex)
367.             {
368.                 System.Diagnostics.Debug.WriteLine($"Failed to receive notification: {ex.Message}");
369.                 return null;
370.             }
371.         }
372. 
373.         public void MarkAsRead(int notificationId)
374.         {
375.             // No-op for in-memory implementation (persistence not implemented)
376.         }
377. 
378.         private string GenerateMessage(string entityType, string entityId, string entityDisplayName, EntityOperation operation)
379.         {
380.             var displayText = !string.IsNullOrWhiteSpace(entityDisplayName)
381.                 ? $"{entityType} '{entityDisplayName}'"
382.                 : $"{entityType} (ID: {entityId})";
383. 
384.             return operation switch
385.             {
386.                 EntityOperation.CREATE => $"New {displayText} has been created",
387.                 EntityOperation.UPDATE => $"{displayText} has been updated",
388.                 EntityOperation.DELETE => $"{displayText} has been deleted",
389.                 _ => $"{displayText} operation: {operation}"
390.             };
391.         }
392. 
393.         public void Dispose()
394.         {
395.             // Nothing to dispose for in-memory queue
396.         }
397.     }
398. }
