        public void EntityOperation_ToString_ReturnsExpectedNames()
        {
            Assert.AreEqual("CREATE", EntityOperation.CREATE.ToString());
            Assert.AreEqual("UPDATE", EntityOperation.UPDATE.ToString());
            Assert.AreEqual("DELETE", EntityOperation.DELETE.ToString());
        }
    }
}

