using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;

namespace ContosoUniversity.Tests.Services
{
    [TestClass]
    public class NotificationServiceTests
    {
        private NotificationService _service;

        [TestInitialize]
        public void Setup()
        {
            _service = new NotificationService();
            // Drain any leftover notifications from other tests (static queue)
            while (_service.ReceiveNotification() != null) { }
        }

        [TestCleanup]
        public void Cleanup()
        {
            // Drain queue after each test to prevent interference
            while (_service.ReceiveNotification() != null) { }
            _service?.Dispose();
        }

        [TestMethod]
        public void SendNotification_SimpleOverload_CreatesNotification()
        {
            // Act
            _service.SendNotification("Student", "1", EntityOperation.CREATE, "testUser");
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("1", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("testUser", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
        }

        [TestMethod]
        public void SendNotification_WithDisplayName_IncludesNameInMessage()
        {
            // Act
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "testUser");
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.Message.Contains("John Doe"));
        }

        [TestMethod]
        public void SendNotification_WithNullUserName_DefaultsToSystem()
        {
            // Act
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.IsNotNull(notification);
            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        public void ReceiveNotification_WhenEmpty_ReturnsNull()
        {
            var notification = _service.ReceiveNotification();
            Assert.IsNull(notification);
        }

        [TestMethod]
        public void ReceiveNotification_WithNotification_ReturnsAndRemovesFromQueue()
        {
            // Arrange
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            // Act
            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();

            // Assert
            Assert.IsNotNull(first);
            Assert.IsNull(second);
        }

        [TestMethod]
        public void SendNotification_CREATE_WithoutDisplayName_GeneratesCorrectMessage()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            Assert.AreEqual("New Student (ID: 1) has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_UPDATE_WithoutDisplayName_GeneratesCorrectMessage()
        {
            _service.SendNotification("Student", "1", EntityOperation.UPDATE);
            var notification = _service.ReceiveNotification();

            Assert.AreEqual("Student (ID: 1) has been updated", notification.Message);
        }

        [TestMethod]
        public void SendNotification_DELETE_WithoutDisplayName_GeneratesCorrectMessage()
        {
            _service.SendNotification("Student", "1", EntityOperation.DELETE);
            var notification = _service.ReceiveNotification();

            Assert.AreEqual("Student (ID: 1) has been deleted", notification.Message);
        }

        [TestMethod]
        public void SendNotification_CREATE_WithDisplayName_GeneratesCorrectMessage()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            Assert.AreEqual("New Student 'John Doe' has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_UPDATE_WithDisplayName_GeneratesCorrectMessage()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.UPDATE);
            var notification = _service.ReceiveNotification();

            Assert.AreEqual("Student 'John Doe' has been updated", notification.Message);
        }

        [TestMethod]
        public void SendNotification_DELETE_WithDisplayName_GeneratesCorrectMessage()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.DELETE);
            var notification = _service.ReceiveNotification();

            Assert.AreEqual("Student 'John Doe' has been deleted", notification.Message);
        }

        [TestMethod]
        public void SendNotification_SetsCreatedAtToApproximatelyNow()
        {
            // Arrange
            var before = DateTime.Now.AddSeconds(-1);

            // Act
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now.AddSeconds(1);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after,
                $"CreatedAt {notification.CreatedAt} should be between {before} and {after}");
        }

        [TestMethod]
        public void SendNotification_SetsIsReadToFalse()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            Assert.IsFalse(notification.IsRead);
        }

        [TestMethod]
        public void SendNotification_QueueCapEnforcement_LimitsQueueSize()
        {
            // Arrange - send more than 500 notifications
            for (int i = 0; i < 510; i++)
            {
                _service.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
            }

            // Act - count remaining
            int count = 0;
            while (_service.ReceiveNotification() != null)
            {
                count++;
            }

            // Assert - should be at most 500
            Assert.IsTrue(count <= 500, $"Queue should be capped at 500, but had {count} items");
        }

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op, should not throw for any ID
            _service.MarkAsRead(1);
            _service.MarkAsRead(0);
            _service.MarkAsRead(-1);
            _service.MarkAsRead(int.MaxValue);
        }

        [TestMethod]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            service.Dispose();
            // No assertion needed - just verifying no exception
        }

        [TestMethod]
        public void Dispose_CanBeCalledMultipleTimes()
        {
            var service = new NotificationService();
            service.Dispose();
            service.Dispose();
        }

        [TestMethod]
        public void SendNotification_MultipleNotifications_MaintainsFIFOOrder()
        {
            // Arrange & Act
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            _service.SendNotification("Course", "2", EntityOperation.UPDATE);
            _service.SendNotification("Department", "3", EntityOperation.DELETE);

            // Assert
            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();
            var third = _service.ReceiveNotification();

            Assert.AreEqual("Student", first.EntityType);
            Assert.AreEqual("Course", second.EntityType);
            Assert.AreEqual("Department", third.EntityType);
        }

        [TestMethod]
        public void SendNotification_WithEmptyDisplayName_UsesIdFormat()
        {
            _service.SendNotification("Student", "1", "", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            Assert.AreEqual("New Student (ID: 1) has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithWhitespaceDisplayName_UsesIdFormat()
        {
            _service.SendNotification("Student", "1", "   ", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            Assert.AreEqual("New Student (ID: 1) has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithNullDisplayName_UsesIdFormat()
        {
            _service.SendNotification("Student", "1", null, EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            Assert.AreEqual("New Student (ID: 1) has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_DifferentEntityTypes_IncludesEntityTypeInMessage()
        {
            // Act
            _service.SendNotification("Course", "100", "Chemistry", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.IsTrue(notification.Message.Contains("Course"));
        }

        [TestMethod]
        public void SendNotification_SetsOperationAsString()
        {
            _service.SendNotification("Student", "1", EntityOperation.UPDATE);
            var notification = _service.ReceiveNotification();

            Assert.AreEqual("UPDATE", notification.Operation);
        }
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public class PaginatedListTests
    {
        [TestMethod]
        public void Constructor_SetsPageIndex()
        {
            var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 10, 2, 3);
            Assert.AreEqual(2, list.PageIndex);
        }

        [TestMethod]
        [DataRow(10, 5, 2)]   // ceil(10/5) = 2
        [DataRow(10, 3, 4)]   // ceil(10/3) = 4
        [DataRow(10, 10, 1)]  // ceil(10/10) = 1
        [DataRow(1, 10, 1)]   // ceil(1/10) = 1
        [DataRow(0, 10, 0)]   // ceil(0/10) = 0
        [DataRow(11, 5, 3)]   // ceil(11/5) = 3
        [DataRow(100, 25, 4)] // ceil(100/25) = 4
        public void Constructor_CalculatesTotalPagesCorrectly(int count, int pageSize, int expectedPages)
        {
            var list = new PaginatedList<int>(new List<int>(), count, 1, pageSize);
            Assert.AreEqual(expectedPages, list.TotalPages);
        }

        [TestMethod]
        public void Constructor_AddsItemsToList()
        {
            var items = new List<int> { 1, 2, 3 };
            var list = new PaginatedList<int>(items, 10, 1, 5);

            Assert.AreEqual(3, list.Count);
            CollectionAssert.AreEqual(items, list);
        }

        [TestMethod]
        public void HasPreviousPage_OnFirstPage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
            Assert.IsFalse(list.HasPreviousPage);
        }

        [TestMethod]
        [DataRow(2)]
        [DataRow(3)]
        [DataRow(10)]
        public void HasPreviousPage_OnLaterPages_ReturnsTrue(int pageIndex)
        {
            var list = new PaginatedList<int>(new List<int>(), 100, pageIndex, 5);
            Assert.IsTrue(list.HasPreviousPage);
        }

        [TestMethod]
        public void HasNextPage_OnLastPage_ReturnsFalse()
        {
            // 10 items, pageSize 5 = 2 pages, on page 2
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
            Assert.IsFalse(list.HasNextPage);
        }

        [TestMethod]
        public void HasNextPage_NotOnLastPage_ReturnsTrue()
        {
            // 10 items, pageSize 5 = 2 pages, on page 1
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
            Assert.IsTrue(list.HasNextPage);
        }

        [TestMethod]
        public void HasPreviousPage_HasNextPage_SinglePage_BothFalse()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 1, 1, 10);
            Assert.IsFalse(list.HasPreviousPage);
            Assert.IsFalse(list.HasNextPage);
        }

        [TestMethod]
        public void Create_ReturnsCorrectPageItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 20).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 2, 5);

            // Assert
            Assert.AreEqual(2, result.PageIndex);
            Assert.AreEqual(4, result.TotalPages);
            Assert.AreEqual(5, result.Count);
            CollectionAssert.AreEqual(new List<int> { 6, 7, 8, 9, 10 }, result.ToList());
        }

        [TestMethod]
        public void Create_FirstPage_ReturnsFirstItems()
        {
            var source = Enumerable.Range(1, 10).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 3);

            Assert.AreEqual(1, result.PageIndex);
            Assert.AreEqual(4, result.TotalPages);
            CollectionAssert.AreEqual(new List<int> { 1, 2, 3 }, result.ToList());
        }

        [TestMethod]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            var source = Enumerable.Range(1, 10).AsQueryable();
            var result = PaginatedList<int>.Create(source, 4, 3);

            Assert.AreEqual(4, result.PageIndex);
            Assert.AreEqual(1, result.Count);
            CollectionAssert.AreEqual(new List<int> { 10 }, result.ToList());
        }

        [TestMethod]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = Enumerable.Empty<int>().AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.AreEqual(0, result.Count);
            Assert.AreEqual(0, result.TotalPages);
            Assert.IsFalse(result.HasPreviousPage);
            Assert.IsFalse(result.HasNextPage);
        }

        [TestMethod]
        public void Create_MiddlePage_HasBothPreviousAndNext()
        {
            var source = Enumerable.Range(1, 30).AsQueryable();
            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.IsTrue(result.HasPreviousPage);
            Assert.IsTrue(result.HasNextPage);
        }

        [TestMethod]
        public void Create_SingleItemPerPage_CorrectTotalPages()
        {
            var source = Enumerable.Range(1, 5).AsQueryable();
            var result = PaginatedList<int>.Create(source, 3, 1);

            Assert.AreEqual(5, result.TotalPages);
            Assert.AreEqual(1, result.Count);
            Assert.AreEqual(3, result[0]);
        }

        [TestMethod]
        public void Create_PageSizeLargerThanSource_ReturnsSinglePage()
        {
            var source = Enumerable.Range(1, 3).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 100);

            Assert.AreEqual(1, result.TotalPages);
            Assert.AreEqual(3, result.Count);
            Assert.IsFalse(result.HasPreviousPage);
            Assert.IsFalse(result.HasNextPage);
        }

        [TestMethod]
        public void Create_WithStrings_WorksCorrectly()
        {
            var source = new[] { "alpha", "beta", "gamma", "delta", "epsilon" }.AsQueryable();
            var result = PaginatedList<string>.Create(source, 1, 2);

            Assert.AreEqual(3, result.TotalPages);
            Assert.AreEqual(2, result.Count);
            CollectionAssert.AreEqual(new List<string> { "alpha", "beta" }, result.ToList());
        }
    }
}

