+using Microsoft.VisualStudio.TestTools.UnitTesting;
+using System.Collections.Generic;
+using System.Linq;
+
+namespace ContosoUniversity.Tests
+{
+    [TestClass]
+    public class PaginatedListTests
+    {
+        [TestMethod]
+        public void Constructor_SetsPageIndex()
+        {
+            var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 10, 2, 3);
+            Assert.AreEqual(2, list.PageIndex);
+        }
+
+        [TestMethod]
+        [DataRow(10, 5, 2)]   // ceil(10/5) = 2
+        [DataRow(10, 3, 4)]   // ceil(10/3) = 4
+        [DataRow(10, 10, 1)]  // ceil(10/10) = 1
+        [DataRow(1, 10, 1)]   // ceil(1/10) = 1
+        [DataRow(0, 10, 0)]   // ceil(0/10) = 0
+        [DataRow(11, 5, 3)]   // ceil(11/5) = 3
+        [DataRow(100, 25, 4)] // ceil(100/25) = 4
+        public void Constructor_CalculatesTotalPagesCorrectly(int count, int pageSize, int expectedPages)
+        {
+            var list = new PaginatedList<int>(new List<int>(), count, 1, pageSize);
+            Assert.AreEqual(expectedPages, list.TotalPages);
+        }
+
+        [TestMethod]
+        public void Constructor_AddsItemsToList()
+        {
+            var items = new List<int> { 1, 2, 3 };
