+            Assert.IsFalse(list.HasPreviousPage);
+        }
+
+        [TestMethod]
+        [DataRow(2)]
+        [DataRow(3)]
+        [DataRow(10)]
+        public void HasPreviousPage_OnLaterPages_ReturnsTrue(int pageIndex)
+        {
+            var list = new PaginatedList<int>(new List<int>(), 100, pageIndex, 5);
+            Assert.IsTrue(list.HasPreviousPage);
+        }
+
+        [TestMethod]
+        public void HasNextPage_OnLastPage_ReturnsFalse()
+        {
+            // 10 items, pageSize 5 = 2 pages, on page 2
+            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
+            Assert.IsFalse(list.HasNextPage);
+        }
+
+        [TestMethod]
+        public void HasNextPage_NotOnLastPage_ReturnsTrue()
+        {
+            // 10 items, pageSize 5 = 2 pages, on page 1
+            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
+            Assert.IsTrue(list.HasNextPage);
+        }
+
+        [TestMethod]
+        public void HasPreviousPage_HasNextPage_SinglePage_BothFalse()
+        {
+            var list = new PaginatedList<int>(new List<int> { 1 }, 1, 1, 10);
+            Assert.IsFalse(list.HasPreviousPage);
+            Assert.IsFalse(list.HasNextPage);
+        }
+
+        [TestMethod]
+        public void Create_ReturnsCorrectPageItems()
+        {
+            // Arrange
+            var source = Enumerable.Range(1, 20).AsQueryable();
+
+            // Act
+            var result = PaginatedList<int>.Create(source, 2, 5);
+
+            // Assert
+            Assert.AreEqual(2, result.PageIndex);
+            Assert.AreEqual(4, result.TotalPages);
+            Assert.AreEqual(5, result.Count);
+            CollectionAssert.AreEqual(new List<int> { 6, 7, 8, 9, 10 }, result.ToList());
+        }
+
+        [TestMethod]
+        public void Create_FirstPage_ReturnsFirstItems()
+        {
+            var source = Enumerable.Range(1, 10).AsQueryable();
+            var result = PaginatedList<int>.Create(source, 1, 3);
+
+            Assert.AreEqual(1, result.PageIndex);
+            Assert.AreEqual(4, result.TotalPages);
+            CollectionAssert.AreEqual(new List<int> { 1, 2, 3 }, result.ToList());
+        }
+
+        [TestMethod]
+        public void Create_LastPage_ReturnsRemainingItems()
+        {
+            var source = Enumerable.Range(1, 10).AsQueryable();
+            var result = PaginatedList<int>.Create(source, 4, 3);
+
+            Assert.AreEqual(4, result.PageIndex);
+            Assert.AreEqual(1, result.Count);
+            CollectionAssert.AreEqual(new List<int> { 10 }, result.ToList());
+        }
+
+        [TestMethod]
+        public void Create_EmptySource_ReturnsEmptyList()
+        {
+            var source = Enumerable.Empty<int>().AsQueryable();
+            var result = PaginatedList<int>.Create(source, 1, 5);
+
+            Assert.AreEqual(0, result.Count);
+            Assert.AreEqual(0, result.TotalPages);
+            Assert.IsFalse(result.HasPreviousPage);
+            Assert.IsFalse(result.HasNextPage);
+        }
+
+        [TestMethod]
+        public void Create_MiddlePage_HasBothPreviousAndNext()
+        {
+            var source = Enumerable.Range(1, 30).AsQueryable();
+            var result = PaginatedList<int>.Create(source, 2, 10);
+
+            Assert.IsTrue(result.HasPreviousPage);
+            Assert.IsTrue(result.HasNextPage);
+        }
+
+        [TestMethod]
+        public void Create_SingleItemPerPage_CorrectTotalPages()
+        {
+            var source = Enumerable.Range(1, 5).AsQueryable();
+            var result = PaginatedList<int>.Create(source, 3, 1);
+
+            Assert.AreEqual(5, result.TotalPages);
+            Assert.AreEqual(1, result.Count);
+            Assert.AreEqual(3, result[0]);
+        }
+
+        [TestMethod]
+        public void Create_PageSizeLargerThanSource_ReturnsSinglePage()
+        {
+            var source = Enumerable.Range(1, 3).AsQueryable();
+            var result = PaginatedList<int>.Create(source, 1, 100);
+
+            Assert.AreEqual(1, result.TotalPages);
+            Assert.AreEqual(3, result.Count);
+            Assert.IsFalse(result.HasPreviousPage);
+            Assert.IsFalse(result.HasNextPage);
+        }
+
+        [TestMethod]
+        public void Create_WithStrings_WorksCorrectly()
+        {
+            var source = new[] { "alpha", "beta", "gamma", "delta", "epsilon" }.AsQueryable();
+            var result = PaginatedList<string>.Create(source, 1, 2);
+
+            Assert.AreEqual(3, result.TotalPages);
+            Assert.AreEqual(2, result.Count);
+            CollectionAssert.AreEqual(new List<string> { "alpha", "beta" }, result.ToList());
+        }
+    }
+}
