            _context.Students.AddRange(
                new Student { FirstMidName = "A", LastName = "B", EnrollmentDate = sameDate },
                new Student { FirstMidName = "C", LastName = "D", EnrollmentDate = sameDate }
            );
            _context.SaveChanges();

            // Act
            var result = _controller.About() as ViewResult;
            var model = result.Model as List<EnrollmentDateGroup>;

            // Assert
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual(2, model[0].StudentCount);
        }

        [TestMethod]
        public void About_NoStudents_ReturnsEmptyList()
        {
