using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.EntityFrameworkCore;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Moq;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public class StudentsControllerTests
    {
        private SchoolContext _context;
        private StudentsController _controller;

        [TestInitialize]
        public void Setup()
        {
            _context = TestHelpers.CreateInMemoryContext();
            _controller = new StudentsController(_context);
            TestHelpers.SetupControllerContext(_controller);
            TestHelpers.DrainNotificationQueue();
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
            TestHelpers.DrainNotificationQueue();
        }

        private void SeedStudents()
        {
            _context.Students.AddRange(
                new Student { FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Parse("2010-09-01") },
                new Student { FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = DateTime.Parse("2012-09-01") },
                new Student { FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = DateTime.Parse("2013-09-01") },
                new Student { FirstMidName = "Gytis", LastName = "Barzdukas", EnrollmentDate = DateTime.Parse("2012-09-01") },
                new Student { FirstMidName = "Yan", LastName = "Li", EnrollmentDate = DateTime.Parse("2012-09-01") }
            );
            _context.SaveChanges();
        }

        #region Index Tests

        [TestMethod]
        public void Index_NoParams_ReturnsViewWithStudentsSortedByLastName()
        {
            SeedStudents();

            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(5, model.Count);
            // Default sort is by LastName ascending
            var names = model.Select(s => s.LastName).ToList();
            var sorted = names.OrderBy(n => n).ToList();
            CollectionAssert.AreEqual(sorted, names);
        }

        [TestMethod]
        public void Index_SortByNameDesc_ReturnsDescendingOrder()
        {
            SeedStudents();

            var result = _controller.Index("name_desc", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.IsNotNull(model);
            var names = model.Select(s => s.LastName).ToList();
            var sorted = names.OrderByDescending(n => n).ToList();
            CollectionAssert.AreEqual(sorted, names);
        }

        [TestMethod]
        public void Index_SortByDate_ReturnsSortedByDateAscending()
        {
            SeedStudents();

            var result = _controller.Index("Date", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.IsNotNull(model);
            var dates = model.Select(s => s.EnrollmentDate).ToList();
            var sorted = dates.OrderBy(d => d).ToList();
            CollectionAssert.AreEqual(sorted, dates);
        }

        [TestMethod]
        public void Index_SortByDateDesc_ReturnsSortedByDateDescending()
        {
            SeedStudents();

            var result = _controller.Index("date_desc", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.IsNotNull(model);
            var dates = model.Select(s => s.EnrollmentDate).ToList();
            var sorted = dates.OrderByDescending(d => d).ToList();
            CollectionAssert.AreEqual(sorted, dates);
        }

        [TestMethod]
        public void Index_SearchByLastName_FiltersResults()
        {
            SeedStudents();

            var result = _controller.Index(null, null, "Alexander", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Alexander", model[0].LastName);
        }

        [TestMethod]
        public void Index_SearchByFirstName_FiltersResults()
        {
            SeedStudents();

            var result = _controller.Index(null, null, "Carson", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Carson", model[0].FirstMidName);
        }

        [TestMethod]
        public void Index_SearchNoMatch_ReturnsEmpty()
        {
            SeedStudents();

            var result = _controller.Index(null, null, "ZZZ_NoMatch", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.IsNotNull(model);
            Assert.AreEqual(0, model.Count);
        }

        [TestMethod]
        public void Index_Pagination_FirstPageOfMany()
        {
            // Add 15 students to test pagination (pageSize = 10)
            for (int i = 0; i < 15; i++)
            {
                _context.Students.Add(new Student
                {
                    FirstMidName = $"Student{i}",
                    LastName = $"Last{i:D2}",
                    EnrollmentDate = DateTime.Today
                });
            }
            _context.SaveChanges();

            var result = _controller.Index(null, null, null, 1) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.AreEqual(10, model.Count);
            Assert.IsTrue(model.HasNextPage);
            Assert.IsFalse(model.HasPreviousPage);
        }

        [TestMethod]
        public void Index_Pagination_SecondPage()
        {
            for (int i = 0; i < 15; i++)
            {
                _context.Students.Add(new Student
                {
                    FirstMidName = $"Student{i}",
                    LastName = $"Last{i:D2}",
                    EnrollmentDate = DateTime.Today
                });
            }
            _context.SaveChanges();

            var result = _controller.Index(null, null, null, 2) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.AreEqual(5, model.Count);
            Assert.IsTrue(model.HasPreviousPage);
            Assert.IsFalse(model.HasNextPage);
        }

        [TestMethod]
        public void Index_NewSearchString_ResetsToPage1()
        {
            SeedStudents();

            var result = _controller.Index(null, null, "A", 5) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.AreEqual(1, model.PageIndex);
        }

        [TestMethod]
        public void Index_NullSearchString_UsesCurrentFilter()
        {
            SeedStudents();

            var result = _controller.Index(null, "Alexander", null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.AreEqual(1, model.Count);
        }

        [TestMethod]
        public void Index_SetsViewBagSortParameters()
        {
            SeedStudents();

            _controller.Index(null, null, null, null);

            Assert.AreEqual("name_desc", _controller.ViewBag.NameSortParm);
            Assert.AreEqual("Date", _controller.ViewBag.DateSortParm);
        }

        [TestMethod]
        public void Index_NameDescSort_SetsNameSortParmToEmpty()
        {
            SeedStudents();

            _controller.Index("name_desc", null, null, null);

            Assert.AreEqual("", _controller.ViewBag.NameSortParm);
        }

        [TestMethod]
        public void Index_DateSort_SetsDateSortParmToDateDesc()
        {
            SeedStudents();

            _controller.Index("Date", null, null, null);

            Assert.AreEqual("date_desc", _controller.ViewBag.DateSortParm);
        }

        [TestMethod]
        public void Index_SetsViewBagCurrentFilter()
        {
            SeedStudents();

            _controller.Index(null, null, "test", null);

            Assert.AreEqual("test", _controller.ViewBag.CurrentFilter);
        }

        #endregion

        #region Details Tests

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null) as StatusCodeResult;

            Assert.IsNotNull(result);
            Assert.AreEqual(400, result.StatusCode);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            _context.Students.Add(new Student
            {
                FirstMidName = "Test",
                LastName = "User",
                EnrollmentDate = DateTime.Today,
                Enrollments = new List<Enrollment>()
            });
            _context.SaveChanges();
            var student = _context.Students.First();

            var result = _controller.Details(student.ID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual("Test", model.FirstMidName);
        }

        [TestMethod]
        public void Details_NonExistentId_ThrowsInvalidOperationException()
        {
            // .Single() throws when no element is found
            Assert.ThrowsException<InvalidOperationException>(() =>
            {
                _controller.Details(999);
            });
        }

        #endregion

        #region Create Tests

        [TestMethod]
        public void Create_GET_ReturnsViewWithDefaultDate()
        {
            var result = _controller.Create() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual(DateTime.Today, model.EnrollmentDate);
        }

        [TestMethod]
        public void Create_POST_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                FirstMidName = "New",
                LastName = "Student",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Create(student) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }

        [TestMethod]
        public void Create_POST_ValidStudent_SavesStudentToDatabase()
        {
            var student = new Student
            {
                FirstMidName = "New",
                LastName = "Student",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            _controller.Create(student);

            Assert.AreEqual(1, _context.Students.Count());
            Assert.AreEqual("New", _context.Students.First().FirstMidName);
        }

        [TestMethod]
        public void Create_POST_MinValueDate_ReturnsViewWithModelError()
        {
            var student = new Student
            {
                FirstMidName = "New",
                LastName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsFalse(_controller.ModelState.IsValid);
        }

        [TestMethod]
        public void Create_POST_DateBefore1753_ReturnsViewWithModelError()
        {
            var student = new Student
            {
                FirstMidName = "New",
                LastName = "Student",
                EnrollmentDate = new DateTime(1752, 12, 31)
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsTrue(_controller.ModelState.ErrorCount > 0);
        }

        [TestMethod]
        public void Create_POST_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                FirstMidName = "New",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.IsNotNull(result);
        }

