using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.EntityFrameworkCore;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Moq;
using System;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public class NotificationsControllerTests
    {
        private SchoolContext _context;
        private NotificationsController _controller;

        [TestInitialize]
        public void Setup()
        {
            _context = TestHelpers.CreateInMemoryContext();
            _controller = new NotificationsController(_context);
            TestHelpers.SetupControllerContext(_controller);
            TestHelpers.DrainNotificationQueue();
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
            TestHelpers.DrainNotificationQueue();
        }

        [TestMethod]
        public void GetNotifications_NoNotifications_ReturnsEmptyList()
        {
            var result = _controller.GetNotifications();

            Assert.IsNotNull(result);
            var jsonResult = result as JsonResult;
            Assert.IsNotNull(jsonResult);
        }

        [TestMethod]
        public void GetNotifications_WithNotifications_ReturnsNotifications()
        {
            // Arrange - add notifications to the static queue
            var service = new NotificationService();
            service.SendNotification("Student", "1", "John", EntityOperation.CREATE);
            service.SendNotification("Course", "2", "Chemistry", EntityOperation.UPDATE);

            // Act
            var result = _controller.GetNotifications() as JsonResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.IsNotNull(result.Value);
        }

        [TestMethod]
        public void GetNotifications_ReturnsAtMost10()
        {
            // Arrange - add more than 10 notifications
            var service = new NotificationService();
            for (int i = 0; i < 15; i++)
            {
                service.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
            }

            // Act
            var result = _controller.GetNotifications() as JsonResult;

            // Assert - the controller reads up to 10 from the queue
            Assert.IsNotNull(result);
            // After reading 10, there should be 5 left in the queue
            int remaining = 0;
            while (service.ReceiveNotification() != null) remaining++;
            Assert.AreEqual(5, remaining);
        }

        [TestMethod]
        public void MarkAsRead_ReturnsJsonSuccess()
        {
            var result = _controller.MarkAsRead(1) as JsonResult;

            Assert.IsNotNull(result);
            Assert.IsNotNull(result.Value);
        }

        [TestMethod]
        public void MarkAsRead_AnyId_DoesNotThrow()
        {
            // MarkAsRead is a no-op on the notification service
            _controller.MarkAsRead(1);
            _controller.MarkAsRead(0);
            _controller.MarkAsRead(-1);
            _controller.MarkAsRead(int.MaxValue);
        }

        [TestMethod]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();

            Assert.IsInstanceOfType(result, typeof(ViewResult));
        }

        [TestMethod]
        public void GetNotifications_RemovesNotificationsFromQueue()
        {
            // Arrange
            var service = new NotificationService();
            service.SendNotification("Student", "1", EntityOperation.CREATE);

            // Act
            _controller.GetNotifications();

            // Assert - queue should be drained
            var remaining = service.ReceiveNotification();
            Assert.IsNull(remaining);
        }

        [TestMethod]
        public void GetNotifications_MultipleCallsOnEmptyQueue_ReturnSafely()
        {
            // Call multiple times on empty queue - should not throw
            _controller.GetNotifications();
            _controller.GetNotifications();
            _controller.GetNotifications();
        }
    }
}

